import { writeFileSync, mkdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
const __dirname = dirname(fileURLToPath(import.meta.url));
const w = (dir, slug, obj) => {
  mkdirSync(join(__dirname, dir), { recursive: true });
  writeFileSync(join(__dirname, dir, slug + '.json'), JSON.stringify(obj, null, 2));
  console.log('  ✓ ' + slug);
};
console.log('\n=== profiles_v6 ===');
w('profiles_v6','3m',{"brand_name":"3M","brand_slug":"3m","parent_company":"3M Company","ultimate_parent":"3M Company","overall_concern_level":"significant","profile_type":"database","generated_headline":"3M KNEW PFAS CHEMICALS CAUSED CANCER IN THE 1970S — KEPT MAKING THEM FOR DECADES — AND PAID $10.3 BILLION FOR CONTAMINATING DRINKING WATER ACROSS AMERICA","executive_summary":"3M Company invented PFAS — synthetic 'forever chemicals' that do not break down in the environment or the human body — in the 1940s. Internal 3M documents revealed through litigation showed the company discovered PFAS were accumulating in human blood globally by the 1970s and documented health concerns including cancer associations. 3M continued manufacturing PFAS for decades. In June 2023, 3M agreed to pay $10.3 billion over 13 years to settle claims from US public water systems contaminated by PFAS. Separately, 3M's subsidiary Aearo Technologies manufactured Combat Arms dual-ended earplugs sold to the US military between 2003 and 2015 with a design defect that 3M knew about before sale. In August 2023, 3M agreed to pay $6 billion — later increased to $9.1 billion — to settle claims from approximately 250,000 US military veterans who suffered hearing damage.","verdict_tags":["10_3b_pfas_water_settlement_13_years","9_1b_military_earplug_settlement_250000_veterans","pfas_health_risk_known_1970s_continued_manufacturing","forever_chemicals_cannot_break_down","aearo_technologies_defective_earplug_known_defect","20b_total_recent_settlements"],"concern_flags":{"labor":false,"environmental":true,"political":true,"tax":true,"health":true,"legal":true},"labor":{"summary":"3M employs approximately 85,000 people globally. Workers at 3M's PFAS manufacturing facilities — including its Decatur, Alabama plant — have documented elevated rates of PFAS-related illness including cancer.","flags":["manufacturing_worker_pfas_exposure_documented"],"sources":[]},"environmental":{"summary":"PFAS contamination from 3M's manufacturing and product use is documented in drinking water sources across the United States and globally. Military bases where 3M's aqueous film-forming foam (AFFF) was used for firefighting training have documented PFAS contamination of surrounding groundwater. PFAS do not break down in the environment — contamination is effectively permanent without active remediation.","flags":["pfas_permanent_contamination_water_systems_nationwide","military_base_afff_contamination_hundreds_installations","minnesota_897m_separate_state_settlement"],"sources":[]},"political":{"summary":"3M has lobbied extensively against PFAS regulation — opposing EPA maximum contaminant level standards for PFAS in drinking water and resisting state-level restrictions on PFAS-containing products. The company funded third-party research challenging the health effects of PFAS.","flags":["pfas_regulation_lobbying_documented","third_party_research_health_effect_challenging"],"sources":[]},"legal":{"summary":"June 2023: 3M agreed to pay $10.3 billion over 13 years to settle class action claims from public water systems contaminated by PFAS. August 2023: 3M agreed to pay between $6 billion and $9.1 billion to approximately 250,000 US military veterans who suffered hearing damage from defective Combat Arms dual-ended earplugs. 3M's subsidiary Aearo Technologies filed for bankruptcy in 2022 to limit earplug liability — the bankruptcy was dismissed by a judge who found it lacked good faith. Separate state PFAS settlements include Minnesota ($897 million, 2018).","flags":["10_3b_pfas_water_class_action_settlement","9_1b_earplug_250000_veterans","aearo_texas_two_step_dismissed_good_faith","known_defect_before_earplug_sale","20b_total_obligations"],"sources":["https://news.3m.com/2023-06-22-3M-Agrees-to-Resolve-PFAS-Claims-by-Water-Utilities-for-10-3B"]},"tax":{"summary":"3M has historically maintained effective tax rates below the US statutory corporate rate through international profit allocation structures. 3M's $10.3 billion PFAS settlement payments are spread over 13 years and may be substantially tax-deductible — meaning US taxpayers partially subsidize a penalty for contaminating their own water systems.","flags":["pfas_settlement_deductibility_taxpayer_subsidy"],"sources":[]},"executives":{"summary":"CEO Mike Roman has led 3M through the PFAS and earplug settlements and the Solventum healthcare spinoff. 3M's attempt to use Aearo Technologies' Texas Two-Step bankruptcy was rejected by the court as lacking good faith, requiring 3M to settle from its own balance sheet.","flags":["texas_two_step_rejected_good_faith_failed","no_executive_criminal_charges_known_1970s_health_risks"],"sources":[]},"connections":{"summary":"3M's PFAS chemicals are used in thousands of products from dozens of manufacturers. DuPont and its spinoffs (Chemours, Corteva) face separate massive PFAS liability. The military's use of AFFF firefighting foam — for which 3M was a primary supplier — has contaminated groundwater at hundreds of US military installations. 3M's earplug case directly parallels J&J's talc Texas Two-Step attempt — both rejected.","flags":["pfas_industry_wide_problem_3m_originated","jnj_talc_texas_two_step_parallel"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Internal 3M documents obtained in litigation have shown that 3M scientists documented PFAS accumulation in human blood in the early 1970s, conducted animal studies showing health effects, and continued manufacturing for decades. Plaintiffs have alleged that 3M engaged in a deliberate campaign to suppress and discredit scientific evidence of PFAS harm while lobbying against regulation.","flags":["1970s_blood_accumulation_documented_continued_manufacturing","scientific_evidence_suppression_alleged"],"sources":["https://www.ewg.org/news-insights/news/2020/11/3m-knew-about-pfas-dangers-decades-ago"]},"health_record":{"summary":"PFAS are associated with kidney cancer, testicular cancer, thyroid disease, immune system suppression, elevated cholesterol, and reproductive harm. The EPA in 2024 set a maximum contaminant level of 4 parts per trillion for PFAS in drinking water. An estimated 45% of US tap water is contaminated with PFAS. Approximately 250,000 military veterans suffered hearing damage — tinnitus and permanent hearing loss — from defective 3M earplugs.","flags":["45pct_us_tap_water_pfas_contaminated","kidney_testicular_cancer_thyroid_immune_association","250000_veterans_hearing_damage_tinnitus"],"sources":["https://www.epa.gov/pfas/pfas-strategic-roadmap"]},"alternatives":{"cheaper":["PFAS-free cookware: cast iron, stainless steel, carbon steel — cheaper over lifetime than Teflon-coated replacements","PFAS-free water filtration: NSF/ANSI 58 certified reverse osmosis systems remove PFAS from drinking water"],"healthier":["NSF 58-certified reverse osmosis or NSF 53-certified activated carbon filters remove PFAS from drinking water","PFAS-free cookware: cast iron, stainless steel"],"diy":["Check your drinking water PFAS levels: EWG's tap water database at ewg.org/tapwater shows contamination levels by zip code","If you are a veteran who served 2003-2015 and experienced hearing loss: consult a veterans' attorney about ongoing litigation options"]},"timeline":[{"year":1970,"event":"Internal 3M documents show PFAS accumulating in human blood globally; company studies document health concerns","severity":"critical","source_url":""},{"year":2003,"event":"3M subsidiary Aearo Technologies begins supplying Combat Arms CAEv2 earplugs to US military; internal tests show potential loosening defect","severity":"critical","source_url":""},{"year":2018,"event":"$897M Minnesota PFAS settlement for Cottage Grove manufacturing contamination","severity":"critical","source_url":""},{"year":2022,"event":"Aearo Technologies files for bankruptcy Texas Two-Step; court dismisses — lacks good faith","severity":"high","source_url":""},{"year":2023,"event":"June: $10.3B PFAS municipal water systems settlement. August: $6-9.1B earplug settlement for approximately 250,000 US military veterans.","severity":"critical","source_url":"https://news.3m.com/2023-06-22-3M-Agrees-to-Resolve-PFAS-Claims-by-Water-Utilities-for-10-3B"},{"year":2024,"event":"EPA sets 4 ppt PFAS maximum contaminant level; 3M had been documenting health concerns since the 1970s","severity":"critical","source_url":""}],"community_impact":{"displacement":"Communities near 3M manufacturing facilities have documented PFAS contamination in drinking water that has persisted for decades and cannot be fully remediated. Military base communities across the United States face PFAS contamination of groundwater affecting local residents who had no connection to military activities.","price_illusion":"3M products — Post-it notes, Scotch tape, Filtrete filters — are everyday household products. The cost of producing them included PFAS manufacturing operations whose environmental and health consequences 3M's own scientists documented in the 1970s. The consumer price did not include the eventual $10.3 billion cost of cleaning up the drinking water they contaminated.","tax_math":"3M's $10.3 billion PFAS water settlement, paid over 13 years, is partially tax-deductible — meaning the public water systems being compensated for 3M's contamination are partly reimbursed from taxpayer funds that simultaneously subsidize 3M's penalty.","wealth_velocity":"3M is a publicly traded US company with broad institutional and retail shareholder ownership. The profits from PFAS-containing products accumulated over decades when the health consequences were being documented internally."},"cost_absorption":{"who_benefited":[{"group":"3M shareholders","how":"Decades of profits from PFAS products while internal scientists documented health risks; competitive advantage from not disclosing hazards"},{"group":"US military (short-term)","how":"Purchased defective earplugs at lower cost than functional alternatives; longer-term cost is borne by VA healthcare"}],"who_paid":[{"group":"Communities with contaminated drinking water","how":"PFAS in approximately 45% of US tap water; cancer, thyroid, immune, and reproductive health effects documented"},{"group":"Approximately 250,000 US military veterans","how":"Hearing damage — tinnitus and permanent hearing loss — from earplugs with a known defect 3M did not disclose"}],"the_gap":"3M's scientists documented in the 1970s that PFAS was accumulating in human blood globally and showed health effects in animals. 3M kept making PFAS. The EPA set a drinking water standard in 2024 — 50 years later. 3M paid $10.3 billion for contaminating drinking water. They also sold defective earplugs to the military for 12 years. They tried to put the earplug liability in a subsidiary bankruptcy. The court said no. 250,000 veterans have hearing damage."}});
w('profiles_v6','purdue-pharma',{"brand_name":"Purdue Pharma","brand_slug":"purdue-pharma","parent_company":"Purdue Pharma L.P. (bankrupt)","ultimate_parent":"Sackler Family (via trusts and holding companies)","overall_concern_level":"significant","profile_type":"database","generated_headline":"THE SACKLER FAMILY EXTRACTED $10 BILLION FROM PURDUE BEFORE BANKRUPTCY WHILE THEIR OXYCONTIN KILLED HUNDREDS OF THOUSANDS — THE SUPREME COURT SAID THEY CAN'T HIDE BEHIND THE BANKRUPTCY SHIELD","executive_summary":"Purdue Pharma L.P. manufactured OxyContin — the branded extended-release oxycodone formulation whose mass marketing beginning in 1996 is widely documented as the ignition point of the US prescription opioid epidemic. Purdue marketed OxyContin to physicians as safer and less addictive than other opioids — claims the FDA subsequently determined were misleading. Purdue paid $634 million in 2007 to resolve DOJ charges that it misbranded OxyContin. The Sackler family — owners of Purdue — extracted approximately $10-11 billion from the company in dividends before it filed for bankruptcy in 2019 amid 3,000+ lawsuits. The family negotiated a bankruptcy plan that would have shielded them from civil lawsuits in exchange for a $6 billion contribution — a plan the US Supreme Court blocked in June 2024, ruling 5-4 that bankruptcy law cannot extinguish civil claims against parties who have not themselves filed for bankruptcy.","verdict_tags":["634m_2007_oxycontin_misbranding","sackler_10_11b_extraction_before_bankruptcy","supreme_court_2024_blocked_sackler_shield","opioid_epidemic_documented_origin","3000_plus_lawsuits"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":true,"legal":true},"labor":{"summary":"Purdue Pharma employed approximately 1,600 people at its bankruptcy filing. The sales force that marketed OxyContin executed the marketing strategy that generated the fraud finding, without necessarily being aware that the marketing claims were misleading.","flags":["1600_employees_bankruptcy_job_loss"],"sources":[]},"environmental":{"summary":"No major primary environmental enforcement actions against Purdue have been identified.","flags":[],"sources":[]},"political":{"summary":"Purdue lobbied extensively against opioid prescribing restrictions and FDA regulatory oversight. The company funded professional medical organizations, pain management advocacy groups, and patient advocacy organizations that promoted broader opioid prescribing. Purdue's payments to the Joint Commission, which developed pain as 'the fifth vital sign' guidelines, have been documented in academic research.","flags":["medical_organization_funding_prescribing_guidelines","fifth_vital_sign_joint_commission_documented_payments"],"sources":[]},"legal":{"summary":"May 2007: Purdue Pharma and three executives — President Michael Friedman, Chief Legal Officer Howard Udell, and Chief Medical Officer Paul Goldenheim — pleaded guilty to federal charges of misbranding OxyContin. Purdue paid $634 million; the three executives paid $34.5 million and avoided prison. In 2019, Purdue filed for Chapter 11 bankruptcy. The proposed $6 billion Sackler family contribution in exchange for civil lawsuit immunity was blocked by the Supreme Court in June 2024 (5-4).","flags":["634m_2007_misbranding_executives_guilty_plea_no_prison","sackler_6b_civil_immunity_blocked_supreme_court_2024","bankruptcy_non_debtor_shield_ruled_impermissible"],"sources":["https://www.justice.gov/archive/usao/vaw/press_releases/2007/may/purdue_pharma_plea.html","https://www.supremecourt.gov/opinions/23pdf/23-124_jd8c.pdf"]},"tax":{"summary":"The Sackler family's $10-11 billion in dividends extracted from Purdue were managed through a global network of trusts and holding companies designed to minimize US estate and income taxes. The family maintained accounts in Switzerland.","flags":["sackler_global_trust_network_us_tax_minimization","switzerland_accounts_documented"],"sources":[]},"executives":{"summary":"The Sackler family — divided into the 'Raymond' and 'Mortimer' branches — owned Purdue through trusts and controlled its board. Richard Sackler, as president and then board chair, was the primary driver of OxyContin's aggressive marketing strategy. Internal documents revealed in litigation quoted Richard Sackler saying the goal was to 'hammer on the abusers in every way possible' when overdoses became public. No Sackler family member has been criminally charged.","flags":["richard_sackler_hammer_abusers_quote_documented","family_members_no_criminal_charges","2007_executives_avoided_prison"],"sources":["https://www.nytimes.com/2019/01/15/health/sacklers-purdue-oxycontin-opioids.html"]},"connections":{"summary":"Purdue's OxyContin marketing created the prescribing culture that opioid distributors — McKesson, Cencora, Cardinal Health — then amplified through distribution of billions of pills. The Sackler family's philanthropic reputation — built on donations to museums and universities — was used as social legitimacy while the family extracted billions. Many institutions have since removed the Sackler name.","flags":["distributor_ecosystem_mckesson_cencora_connected","sackler_name_removal_museums_universities"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"State attorney general investigations have alleged that the Sackler family was directly involved in specific deceptive marketing decisions at Purdue — not merely passive investors. The New York attorney general alleged the Sackler family secretly transferred approximately $1 billion out of Purdue into accounts in Switzerland in the years leading up to bankruptcy specifically to insulate it from litigation.","flags":["richard_sackler_marketing_direction_alleged","1b_transfer_switzerland_pre_bankruptcy_ny_ag_alleged"],"sources":[]},"health_record":{"summary":"Approximately 500,000 Americans died of opioid overdoses between 1999 and 2019. The CDC identifies the prescription opioid wave (1999-2010) as the first of three overlapping overdose waves. Purdue's marketing claimed OxyContin had less than 1% addiction rate — a figure derived from a single letter to a medical journal that Purdue's sales force cited as clinical evidence for years. The claim was false.","flags":["500000_overdose_deaths_opioid_crisis","less_than_1pct_addiction_claim_documented_false"],"sources":["https://www.cdc.gov/opioids/data/analysis-resources.html"]},"alternatives":{"cheaper":["OxyContin is off-patent — generic oxycodone is available. For patients with legitimate pain needs, the medication class exists without the Purdue brand."],"healthier":["Multimodal pain management: physical therapy, cognitive behavioral therapy for chronic pain, regional anesthesia, NSAIDs","For opioid use disorder: buprenorphine and methadone — SAMHSA National Helpline 1-800-662-4357"],"diy":["SAMHSA National Helpline: 1-800-662-4357 — free, confidential, 24/7 treatment referral","Naloxone (Narcan) is available without prescription at most pharmacies"]},"timeline":[{"year":1996,"event":"OxyContin approved by FDA and aggressively marketed; sales force trained to tell physicians it is less addictive than other opioids","severity":"critical","source_url":""},{"year":2007,"event":"Purdue pays $634M; three executives plead guilty to misbranding; no prison time","severity":"critical","source_url":"https://www.justice.gov/archive/usao/vaw/press_releases/2007/may/purdue_pharma_plea.html"},{"year":2008,"event":"Sackler family begins accelerating dividend extraction from Purdue; approximately $10-11B extracted 2008-2018","severity":"critical","source_url":""},{"year":2019,"event":"Purdue files Chapter 11 bankruptcy amid 3,000+ lawsuits","severity":"critical","source_url":""},{"year":2024,"event":"June: US Supreme Court blocks Sackler immunity deal 5-4; rules bankruptcy cannot shield non-debtors without consent","severity":"critical","source_url":"https://www.supremecourt.gov/opinions/23pdf/23-124_jd8c.pdf"}],"community_impact":{"displacement":"Communities across Appalachian states and rural America experienced destruction of workforce capacity, family stability, and community cohesion from prescription opioid addiction that OxyContin's marketing contributed to igniting.","price_illusion":"OxyContin was priced and marketed as a breakthrough pain medication with a superior safety profile. The $634 million misbranding settlement established that the safety claims were false.","tax_math":"The Sackler family's $10-11 billion in dividends were managed through global trust structures to minimize US estate and income taxes. The public costs of the opioid epidemic are estimated at over $1 trillion.","wealth_velocity":"The Sackler family extracted $10-11 billion from Purdue Pharma. That wealth supported philanthropic donations to universities and museums globally — donations now being refused or returned by institutions removing the Sackler name."},"cost_absorption":{"who_benefited":[{"group":"Sackler family","how":"$10-11B extracted from Purdue before bankruptcy; Supreme Court blocked permanent immunity but family retained most extracted wealth"},{"group":"Purdue executives 2007","how":"Pleaded guilty to misbranding; paid personal fines totaling $34.5M; avoided prison"}],"who_paid":[{"group":"Approximately 500,000 Americans who died of opioid overdoses","how":"The prescription opioid wave — which OxyContin's marketing contributed to igniting — is the first of three overlapping overdose waves"},{"group":"Opioid victims seeking civil accountability","how":"The Sackler family attempted to extinguish civil claims through bankruptcy shield; Supreme Court blocked it"}],"the_gap":"Purdue told doctors OxyContin had less than a 1% addiction rate. It was false. They pleaded guilty in 2007. Nobody went to prison. The family extracted $10 billion before the bankruptcy. They offered $6 billion for permanent immunity from lawsuits. The Supreme Court said no. The opioid epidemic killed 500,000 people. The Sackler name is still on buildings."}});
w('profiles_v6','glencore',{"brand_name":"Glencore","brand_slug":"glencore","parent_company":"Glencore plc","ultimate_parent":"Glencore plc","overall_concern_level":"significant","profile_type":"database","generated_headline":"GLENCORE PLEADED GUILTY TO BRIBING OFFICIALS IN 7 COUNTRIES AND MANIPULATING OIL MARKETS — THEN PAID $1.5 BILLION GLOBALLY AND KEPT MINING COBALT IN THE CONGO","executive_summary":"Glencore plc is one of the world's largest commodity trading and mining companies, headquartered in Baar, Switzerland. In May 2022, Glencore pleaded guilty to a 7-count criminal information in US District Court covering bribery of foreign government officials in Nigeria, Cameroon, Ivory Coast, Equatorial Guinea, Brazil, Venezuela, and the Democratic Republic of Congo between 2007 and 2018. Glencore paid approximately $1.1 billion to US authorities. Simultaneously, Glencore paid £281 million to the UK Serious Fraud Office, settled with Brazil and Dutch authorities, and admitted to market manipulation of oil prices at US delivery points. The total global resolution exceeded $1.5 billion. Glencore's Democratic Republic of Congo cobalt mining operations — which provide a significant proportion of the cobalt used in smartphone and electric vehicle batteries globally — have been the subject of documented investigations into child labor in artisanal mining activities surrounding Glencore's industrial operations.","verdict_tags":["1_1b_us_doj_bribery_7_countries","281m_uk_sfo_bribery","1_5b_total_global_resolution","oil_market_manipulation_admitted","drc_cobalt_child_labor_artisanal_mining"],"concern_flags":{"labor":true,"environmental":true,"political":true,"tax":true,"health":true,"legal":true},"labor":{"summary":"Glencore's cobalt mining operations in the Democratic Republic of Congo are adjacent to artisanal and small-scale mining operations where child labor has been extensively documented by Amnesty International, Washington Post investigations, and academic researchers. Colombian coal mining operations have involved documented labor disputes and community displacement.","flags":["drc_cobalt_artisanal_child_labor_adjacent_documented","colombia_coal_community_displacement"],"sources":["https://www.amnesty.org/en/documents/afr62/3183/2016/en/"]},"environmental":{"summary":"Glencore is one of the world's largest coal exporters — with significant Australian and Colombian coal operations — placing it among the largest corporate contributors to climate-changing greenhouse gas emissions globally. Tailings dam failures at Zambian copper operations have created environmental contamination.","flags":["worlds_largest_coal_exporters","zambia_copper_tailings_failures"],"sources":[]},"political":{"summary":"The bribery scheme Glencore pleaded guilty to was systematic and senior — involving payments to officials including ministers and heads of state-owned enterprises across seven countries over more than a decade. In the DRC, Glencore paid bribes to obtain mining rights and favorable treatment for its Katanga copper and cobalt operations.","flags":["senior_employee_participation_bribery_multiple_countries","mining_rights_drc_obtained_through_bribery"],"sources":["https://www.justice.gov/opa/pr/glencore-entered-guilty-pleas-foreign-bribery-and-market-manipulation-schemes"]},"legal":{"summary":"May 2022: Glencore plc entered guilty pleas to a 7-count criminal information covering bribery of foreign government officials (FCPA) and commodities fraud (oil market manipulation). US DOJ criminal penalty: $1.11 billion. UK SFO: £281 million. Dutch and Brazilian authorities: additional settlements. Total global: approximately $1.5 billion — the largest FCPA resolution in DOJ history at the time for a commodity company.","flags":["1_11b_us_doj_criminal_penalty","281m_uk_sfo","1_5b_total_global_largest_commodity_company_fcpa"],"sources":["https://www.justice.gov/opa/pr/glencore-entered-guilty-pleas-foreign-bribery-and-market-manipulation-schemes"]},"tax":{"summary":"Glencore's Swiss domicile — in the low-tax canton of Zug — is a standard structure for major commodity trading houses. The company has used transfer pricing between its Swiss trading operations and its mining operations to concentrate profits in low-tax jurisdictions.","flags":["swiss_zug_low_tax_domicile","transfer_pricing_mining_trading_profit_concentration"],"sources":[]},"executives":{"summary":"CEO Gary Nagle succeeded Ivan Glasenberg in June 2021, one year before the guilty pleas. Glasenberg was investigated by the UK SFO but charges were not pursued against him personally. A limited number of executives faced personal criminal charges in the US.","flags":["glasenberg_sfo_investigated_not_charged","corporate_guilty_plea_limited_individual_accountability"],"sources":[]},"connections":{"summary":"Glencore's DRC cobalt operations connect it to the global supply chains for electric vehicle batteries and consumer electronics — cobalt from the DRC passes through Glencore's industrial operations and the surrounding artisanal mining ecosystem to reach battery manufacturers and ultimately into products from Tesla, Apple, Samsung, and every major EV and electronics manufacturer.","flags":["drc_cobalt_ev_consumer_electronics_global_supply_chain","tesla_apple_samsung_downstream_connection"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Human Rights Watch and Amnesty International have alleged that Glencore's industrial cobalt operations in the DRC cannot be meaningfully separated from the artisanal mining ecosystem where child labor is documented. Tax justice researchers have alleged that transfer pricing between Glencore's Swiss trading operations and its DRC and Zambian mining subsidiaries systematically understates the value of extracted resources.","flags":["industrial_artisanal_separation_impossible_alleged","transfer_pricing_resource_country_revenue_deprivation_alleged"],"sources":["https://www.hrw.org/report/2021/11/09/this-is-what-we-die-doing/human-rights-abuses-cobalt-supply-chains"]},"health_record":{"summary":"Artisanal cobalt mining in the DRC involves children working in hand-dug tunnels prone to collapse, without protective equipment. Cobalt dust exposure is associated with 'hard metal lung disease' — a fatal occupational illness. Adult and child artisanal miners absorb this health risk for earnings that human rights organizations have documented as subsistence-level.","flags":["artisanal_child_miner_tunnel_collapse_respiratory_documented","cobalt_dust_hard_metal_lung_disease_fatal"],"sources":["https://www.amnesty.org/en/documents/afr62/3183/2016/en/"]},"alternatives":{"cheaper":["Glencore is a B2B commodity company — consumers do not directly purchase from Glencore. The alternatives are policy-level: mandatory supply chain due diligence for cobalt and coal."],"healthier":["Reduce demand for cobalt through product life extension — keeping smartphones and laptops longer reduces the cobalt demand driving artisanal mining"],"diy":["The Responsible Minerals Initiative (responsibleminerals.org) maintains a database of smelters and refiners with verified sourcing practices","Support organizations working on DRC mining community rights: Global Witness, Amnesty International"]},"timeline":[{"year":2007,"event":"Estimated beginning of systematic bribery program across seven countries per DOJ findings","severity":"critical","source_url":""},{"year":2016,"event":"Amnesty International documents child labor in DRC cobalt artisanal mining adjacent to Glencore's industrial operations","severity":"critical","source_url":"https://www.amnesty.org/en/documents/afr62/3183/2016/en/"},{"year":2021,"event":"Dan Gertler — alleged DRC bribery intermediary — sanctioned by US Treasury OFAC for corruption","severity":"high","source_url":""},{"year":2022,"event":"May: Glencore pleads guilty to 7-count US criminal information; $1.11B US penalty; $281M UK SFO; $1.5B+ total global","severity":"critical","source_url":"https://www.justice.gov/opa/pr/glencore-entered-guilty-pleas-foreign-bribery-and-market-manipulation-schemes"}],"community_impact":{"displacement":"Communities in the DRC's Katanga region face displacement from mining expansion, water contamination from tailings, and the social disruption of artisanal mining economies.","price_illusion":"Glencore's traded commodities are priced on global commodity markets without reflecting the cost of the bribery that secured access to their extraction sites.","tax_math":"Glencore's Swiss trading operations capture the margin on commodity trades while the tax base remains in low-tax Zug. Resource-producing countries collect reduced royalties and taxes due to transfer pricing arrangements.","wealth_velocity":"Glencore's 2011 IPO concentrated wealth for Ivan Glasenberg and other long-term employee-shareholders. The communities in Nigeria, the DRC, and elsewhere whose resources were accessed through bribery received neither the market value of their resources nor the taxes that honest commercial transactions would have generated."},"cost_absorption":{"who_benefited":[{"group":"Glencore shareholders and senior employees","how":"Mining rights and oil contracts in 7 countries obtained through bribery; $1.5B settlement is a fraction of revenues from those operations"}],"who_paid":[{"group":"Resource-producing country governments and citizens","how":"Mining and oil access rights granted for less than fair value through bribery; tax revenues reduced by transfer pricing"},{"group":"DRC artisanal mining community, including children","how":"Occupational hazards in cobalt mining ecosystem adjacent to Glencore's industrial operations"}],"the_gap":"Glencore bribed officials in 7 countries for over a decade. They pleaded guilty. They paid $1.5 billion. The cobalt from their DRC operations goes into electric vehicle batteries and smartphones. Children mine artisanal cobalt adjacent to their industrial operations. Their Swiss headquarters sits in the canton with some of Europe's lowest corporate taxes. The communities in the DRC and Nigeria received none of the $1.5 billion."}});
w('profiles_v6','ikea',{"brand_name":"IKEA","brand_slug":"ikea","parent_company":"INGKA Holding B.V.","ultimate_parent":"Stichting INGKA Foundation (Netherlands)","overall_concern_level":"moderate","profile_type":"database","generated_headline":"IKEA'S OWNERSHIP STRUCTURE IS DESIGNED SO NO INDIVIDUAL OR GOVERNMENT CAN CONTROL IT — AND THE EU ESTIMATED IT AVOIDED €1 BILLION IN TAXES OVER SIX YEARS","executive_summary":"IKEA is the world's largest furniture retailer, operating approximately 460 stores globally under a complex ownership structure deliberately designed to obscure ultimate beneficial ownership and minimize taxation. The company's retail operations are owned by the Stichting INGKA Foundation — a Dutch charitable foundation — which the Economist Intelligence Unit described as 'one of the world's most ingenious tax avoidance structures.' The European Parliament's TAXE committee estimated in 2016 that IKEA's structure allowed it to avoid approximately €1 billion in EU taxes between 2009 and 2014. IKEA's wood supply chain was documented to have sourced wood through Belarus and Ukraine from suppliers connected to illegal logging in protected forests. Following Russia's 2022 invasion of Ukraine, IKEA shut its Russia operations and factories, displacing approximately 12,000 workers. In 2016, six US children were killed by tipping MALM dressers.","verdict_tags":["eu_parliament_1b_tax_avoidance_estimate_2009_2014","stichting_foundation_tax_structure","belarus_ukraine_illegal_logging_documented","russia_ukraine_12000_worker_displacement","malm_dresser_six_child_deaths_recalled"],"concern_flags":{"labor":true,"environmental":true,"political":true,"tax":true,"health":true,"legal":true},"labor":{"summary":"IKEA employs approximately 220,000 people globally (called 'co-workers'). The company's Russia exit displaced approximately 12,000 workers with limited severance. IKEA's model — requiring customers to assemble furniture themselves — externalizes labor cost to consumers.","flags":["12000_russia_workers_displaced_limited_severance","assembly_externalized_labor_cost_to_consumers"],"sources":[]},"environmental":{"summary":"IKEA requires massive quantities of timber annually — it consumes approximately 1% of the world's commercial wood supply. Investigative reporting by the Guardian documented that IKEA's supply chain in Belarus and Ukraine sourced wood through intermediaries connected to illegal logging in protected forests.","flags":["1pct_world_commercial_wood_consumption","belarus_illegal_logging_documented_guardian","ukraine_protected_forest_supply_chain_documented"],"sources":["https://www.theguardian.com/environment/2020/nov/23/ikea-linked-to-illegal-logging-in-ukraine-beeches"]},"political":{"summary":"IKEA's Dutch foundation structure uses royalty payments from its retail operations to Inter IKEA Group (domiciled in Luxembourg, then Liechtenstein) to shift profits to low-tax jurisdictions. The EU Commission has investigated IKEA's Netherlands tax arrangements. IKEA maintained operations in Russia until the 2022 Ukraine invasion.","flags":["eu_commission_netherlands_tax_investigation","inter_ikea_luxembourg_liechtenstein_royalty_structure"],"sources":["https://www.europarl.europa.eu/cmsdata/92481/2016-07-04%20TAXE2%20final%20report.pdf"]},"legal":{"summary":"The EU Commission opened a State Aid investigation into IKEA's Dutch tax arrangements in 2017. The investigation was closed in 2021 without a formal State Aid finding. MALM dresser recall: IKEA recalled MALM dressers in 2016 after six US children died from tip-overs. IKEA initially resisted the US recall while recalling in other markets, ultimately issuing a recall and settling wrongful death claims.","flags":["eu_commission_state_aid_investigation_2017_2021","malm_dresser_six_child_deaths_recall_2016","recall_us_resisted_while_other_markets_recalled"],"sources":["https://www.cpsc.gov/Recalls/2016/ikea-recalls-chests-and-dressers-due-to-serious-tip-over-hazard"]},"tax":{"summary":"IKEA's corporate structure separates the franchise system (Inter IKEA Group) from the retail operations (INGKA Group). Retail stores pay royalties to Inter IKEA. Inter IKEA was domiciled in Luxembourg, then moved to Liechtenstein (1% effective corporate tax). The EU Parliament's 2016 TAXE committee estimated IKEA had avoided approximately €1 billion in EU taxes between 2009 and 2014.","flags":["eu_parliament_1b_tax_avoidance_estimate","inter_ikea_liechtenstein_1pct_effective_rate","stichting_foundation_no_dividend_tax"],"sources":["https://www.europarl.europa.eu/cmsdata/92481/2016-07-04%20TAXE2%20final%20report.pdf"]},"executives":{"summary":"IKEA's ownership structure is deliberately designed so that no individual — including the Kamprad family — has legal ownership or control over the company's assets. Ingvar Kamprad, who founded IKEA in 1943 and died in 2018, established the foundation structure specifically to prevent IKEA from being broken up, sold, or controlled by any individual including his own heirs.","flags":["kamprad_no_individual_ownership_structure_deliberate","foundation_heirs_excluded_deliberate"],"sources":[]},"connections":{"summary":"IKEA's wood supply chain connects it to global timber markets where certification compliance varies significantly by country and supplier. The Belarus sourcing — which continued after international sanctions were applied to the Lukashenko government — connected IKEA's commercial operations to revenue flows benefiting a government that imprisoned political opponents.","flags":["belarus_lukashenko_government_revenue_connection"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Investigative reporters at the Guardian documented in 2020 that IKEA's Ukrainian and Belarusian wood suppliers were sourcing timber from protected forests using fraudulent documentation. Swedish journalists have alleged that IKEA's foundation structure was specifically designed by Ingvar Kamprad with tax avoidance as a primary motivation alongside succession protection.","flags":["protected_forest_fraudulent_documentation_illegal_logging_alleged","foundation_structure_tax_motivation_primary_alleged"],"sources":["https://www.theguardian.com/environment/2020/nov/23/ikea-linked-to-illegal-logging-in-ukraine-beeches"]},"health_record":{"summary":"IKEA has had significant product safety recalls — most notably MALM dressers, which were recalled in 2016 after six children in the US died from the dressers tipping over onto them. IKEA initially resisted the recall in the US while recalling in other markets, ultimately issuing a recall and settlement. The product safety concern was documented in IKEA's engineering testing before the child deaths.","flags":["malm_dresser_six_child_deaths_recalled","recall_us_resisted_while_other_markets_recalled","pre_death_engineering_concerns_documented"],"sources":["https://www.cpsc.gov/Recalls/2016/ikea-recalls-chests-and-dressers-due-to-serious-tip-over-hazard"]},"alternatives":{"cheaper":["Thrift stores and secondhand furniture markets — the most sustainable furniture option at the lowest price point","Local carpenters and furniture makers — often price-competitive with IKEA for quality furniture"],"healthier":["Certified sustainable wood furniture from B Corp furniture companies","Second-hand platforms: Facebook Marketplace, Craigslist, Chairish — genuine circular economy alternative"],"diy":["Check whether your IKEA MALM dresser is covered by the recall — CPSC.gov maintains the full model list","IKEA's as-is section in stores and IKEA second-hand programs offer the product at lower cost with reduced new production impact"]},"timeline":[{"year":1982,"event":"Ingvar Kamprad transfers IKEA ownership to the Stichting INGKA Foundation (Netherlands); no individual owns IKEA","severity":"high","source_url":""},{"year":2016,"event":"Six US children killed by MALM dresser tip-overs; recall issued after initial US resistance. EU Parliament TAXE committee estimates IKEA avoided €1B in EU taxes 2009-2014.","severity":"critical","source_url":""},{"year":2017,"event":"EU Commission opens State Aid investigation into IKEA's Netherlands tax arrangements","severity":"high","source_url":""},{"year":2020,"event":"Guardian investigates IKEA's Belarus and Ukraine wood supply chains; illegal logging in protected forests documented","severity":"high","source_url":""},{"year":2022,"event":"Russia invades Ukraine; IKEA closes Russia stores and factories; 12,000 Russian workers displaced","severity":"high","source_url":""}],"community_impact":{"displacement":"The 12,000 workers employed at IKEA's Russia factories and stores were displaced by the Russia closure. Communities near timber extraction sites in Ukraine and Belarus absorbed the environmental cost of logging.","price_illusion":"IKEA's prices appear competitive because of genuine operational efficiency. The prices are also lower because of tax structures that the EU Parliament estimated avoided €1 billion in European taxes.","tax_math":"The EU Parliament's estimate of €1 billion in avoided EU taxes over six years represents school funding, healthcare funding, and infrastructure funding that IKEA's tax structure reduced.","wealth_velocity":"IKEA's structure deliberately eliminates individual ownership — no Kamprad heir owns IKEA. But the tax efficiency still represents public revenue foregone."},"cost_absorption":{"who_benefited":[{"group":"INGKA Foundation (IKEA's owner)","how":"€1B+ estimated EU tax avoidance through royalty structure; foundation accumulates commercial profits without individual shareholder dividend tax"},{"group":"IKEA customers","how":"Below-market furniture prices enabled partly by operational efficiency and partly by tax structure"}],"who_paid":[{"group":"EU taxpayer-funded public services","how":"Estimated €1B in taxes not collected from IKEA's European operations over six years"},{"group":"Six children killed by MALM dressers and their families","how":"Product safety failure; IKEA initially resisted US recall while recalling in other markets"}],"the_gap":"IKEA's ownership structure is one of the most complex tax arrangements in the world. A Dutch foundation owns a €53 billion retail empire with no individual beneficial owner and no dividend tax. The EU Parliament estimated €1 billion in avoided EU taxes. Six children died from IKEA dressers while IKEA resisted the US recall. Their wood supply chain was documented sourcing from protected forests. The MALM dresser is still the most popular dresser in the world."}});
w('profiles_v6','lactalis',{"brand_name":"Lactalis","brand_slug":"lactalis","parent_company":"Groupe Lactalis","ultimate_parent":"Besnier family (private)","overall_concern_level":"significant","profile_type":"database","generated_headline":"LACTALIS KNEW ITS INFANT FORMULA FACTORY HAD SALMONELLA IN 2005 — KEPT MAKING FORMULA THERE — AND COVERED UP A 2017 OUTBREAK THAT SICKENED BABIES IN 83 COUNTRIES","executive_summary":"Groupe Lactalis is the world's largest dairy company, headquartered in Laval, France, owned entirely by the reclusive Besnier family. In December 2017, Lactalis infant formula produced at its Le Craon factory was contaminated with Salmonella Agona — causing illness in at least 36 infants in France and hundreds internationally across 83 countries. French government investigations subsequently established that the Le Craon factory had experienced a prior Salmonella outbreak in 2005 and that contamination indicators had been present in the years before 2017. Lactalis was found to have continued selling contaminated formula after becoming aware of the contamination. In 2021, a French criminal court convicted Lactalis of aggravated deceit and fined the company. CEO Emmanuel Besnier refused to testify before the French Senate's inquiry committee.","verdict_tags":["83_countries_infant_formula_salmonella","le_craon_factory_2005_prior_salmonella","continued_selling_after_contamination_known","besnier_refused_senate_testimony","2021_french_criminal_conviction"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":true,"legal":true},"labor":{"summary":"Lactalis employs approximately 85,000 people globally across its dairy brands. The family-controlled private structure provides workers with limited transparency about company finances.","flags":[],"sources":[]},"environmental":{"summary":"Lactalis's dairy operations have a significant water and greenhouse gas footprint. Lactalis does not publish comprehensive ESG reporting, consistent with its broader opacity as a private company.","flags":["dairy_emissions_intensive_limited_esg_disclosure"],"sources":[]},"political":{"summary":"Emmanuel Besnier — head of Lactalis and one of Europe's most reclusive billionaires — refused to appear before the French Senate's inquiry commission examining the contaminated formula crisis. The Senate commission voted to have Besnier summoned, but he contested the compulsion to testify.","flags":["besnier_refused_testimony","compelled_summons_contested","private_structure_parliamentary_accountability_limitation"],"sources":[]},"legal":{"summary":"In 2021, a French criminal court convicted Lactalis of 'tromperie aggravée' (aggravated deceit) related to the 2017 salmonella contamination and issued fines. The conviction established that Lactalis knew of contamination risks at the Le Craon factory from its 2005 salmonella history. Court proceedings documented that Lactalis continued to distribute formula products after it had been notified of contamination and after issuing an initial partial recall. Lactalis paid approximately €78 million in compensation to victim families. French court records document over 40 product lot numbers in circulation after the recall announcement.","flags":["2021_french_criminal_conviction_aggravated_deceit","continued_distribution_after_notification_documented","40_plus_lots_in_circulation_post_recall","78m_victim_family_compensation"],"sources":[]},"tax":{"summary":"Lactalis's private, family-owned structure provides minimal public tax disclosure. No major formal tax enforcement actions against Lactalis have been publicly documented.","flags":["private_structure_minimal_tax_disclosure"],"sources":[]},"executives":{"summary":"Emmanuel Besnier has been CEO since 2000, succeeding his father Michel Besnier. The Besnier family is estimated to have a net worth exceeding €22 billion, built almost entirely on Lactalis. Besnier is one of France's most private businessmen — rarely photographed, almost never interviewed, refusing parliamentary testimony.","flags":["besnier_refused_testimony_22b_net_worth","extreme_personal_opacity"],"sources":[]},"connections":{"summary":"Lactalis's global reach through brands like Président, Galbani, and Parmalat means the 2017 contamination affected markets across Europe, Asia, Africa, and Latin America. Retailers in 83 countries received contaminated products.","flags":["83_countries_supply_chain_recall_difficulty"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"French consumer protection investigators have alleged that Lactalis was aware of contamination indicators at the Le Craon factory before December 2017 and did not initiate proactive testing or disclosure. Parent advocacy groups have alleged that Lactalis's initial recall was deliberately limited in scope.","flags":["prior_contamination_indicators_awareness_alleged","deliberately_limited_recall_scope_alleged"],"sources":[]},"health_record":{"summary":"Salmonella Agona in infant formula is particularly dangerous because formula is often the sole food source for newborns. At least 36 infants in France were confirmed ill, with hundreds affected internationally across 83 countries. The Le Craon factory's documented Salmonella history from 2005 — 12 years before the 2017 outbreak — establishes that the contamination risk was known and not adequately addressed.","flags":["formula_sole_food_source_newborn_vulnerability","36_french_infants_hundreds_internationally","12_year_gap_between_known_risk_and_outbreak"],"sources":[]},"alternatives":{"cheaper":["Store brand infant formula — same FDA nutritional requirements as Lactalis brands; different manufacturing chain"],"healthier":["Any infant formula brand with published third-party manufacturing audit results"],"diy":["Check FDA and EFSA recall databases for any current Lactalis product recalls before purchase"]},"timeline":[{"year":2005,"event":"Le Craon factory experiences Salmonella contamination episode — documented in subsequent investigation; not publicly disclosed","severity":"critical","source_url":""},{"year":2017,"event":"December: Salmonella Agona contamination confirmed at Le Craon infant formula factory; 36+ French infants ill","severity":"critical","source_url":""},{"year":2018,"event":"French Senate inquiry; Emmanuel Besnier refuses to testify; recall found inadequate with 40+ lots still circulating; 83 countries found to have received contaminated formula","severity":"critical","source_url":""},{"year":2021,"event":"French criminal court convicts Lactalis of aggravated deceit; fines issued; €78M victim family compensation paid","severity":"critical","source_url":""}],"community_impact":{"displacement":"Infants across 83 countries who consumed contaminated Lactalis formula had no way to know their formula posed a health risk. The recall's documented inadequacy meant that families who attempted to comply with recall guidance may still have received contaminated products.","price_illusion":"Infant formula is priced as a safe, nutritionally complete alternative to breastfeeding. The 2017 crisis established that the Le Craon factory had a known contamination history and that Lactalis continued distributing after the initial contamination notification.","tax_math":"Lactalis's private structure makes precise tax analysis impossible. The family's estimated €22 billion in wealth was built with minimal public disclosure of tax payments.","wealth_velocity":"The Besnier family's estimated €22 billion accumulated from a global dairy business operated with near-complete public opacity. The parents of infants sickened by Lactalis formula received €78 million in compensation — a fraction of the Besnier family's estimated annual wealth growth."},"cost_absorption":{"who_benefited":[{"group":"Besnier family","how":"€22B+ estimated wealth from world's largest dairy company; opacity enabled continued operation after 2005 Salmonella without public accountability until 2017"}],"who_paid":[{"group":"36+ French infants and hundreds internationally","how":"Salmonella illness from formula that was the sole food source for newborns; formula from a factory with documented 12-year contamination history"}],"the_gap":"The Le Craon factory had Salmonella in 2005. Lactalis kept making infant formula there. In 2017 babies got sick from that factory's formula in 83 countries. The recall was documented as inadequate — 40+ contaminated lots kept circulating. The CEO refused to testify before parliament. The company was convicted of aggravated deceit. The family is worth €22 billion. They own the world's largest dairy company. You have probably bought their products today."}});
w('profiles_v6','medtronic',{"brand_name":"Medtronic","brand_slug":"medtronic","parent_company":"Medtronic plc","ultimate_parent":"Medtronic plc","overall_concern_level":"significant","profile_type":"database","generated_headline":"MEDTRONIC PAID $190 MILLION FOR PAYING SURGEONS TO USE ITS SPINAL PRODUCTS — THEN TAX INVERTED TO IRELAND FROM MINNESOTA — ITS INFUSE BONE PROTEIN CAUSED HARM IT PAID TO SUPPRESS","executive_summary":"Medtronic plc is the world's largest medical device company by revenue, originally headquartered in Minneapolis, Minnesota. In 2015, Medtronic completed a $49.9 billion acquisition of Irish medical company Covidien and reincorporated in Dublin, Ireland — one of the most prominent 'tax inversion' transactions in US corporate history. Medtronic has paid multiple DOJ settlements for paying physician kickbacks to prescribe and use its medical devices, including a $190 million settlement in 2017 covering spinal surgery products. The company's INFUSE bone morphogenetic protein product was the subject of a major 2011 Spine journal investigation showing that Medtronic had paid physician-authors of clinical studies on INFUSE who had concealed significant adverse events including cancer risk, ectopic bone growth, and male infertility.","verdict_tags":["190m_spinal_kickback_settlement","49_9b_covidien_tax_inversion_ireland","infuse_adverse_event_suppression_paid_authors","infuse_cancer_ectopic_bone_male_infertility","multiple_doj_kickback_settlements"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":true,"legal":true},"labor":{"summary":"Medtronic employs approximately 90,000 people globally. The company has maintained manufacturing operations in Minnesota following the Ireland reincorporation.","flags":[],"sources":[]},"environmental":{"summary":"Medtronic's pharmaceutical manufacturing generates chemical waste streams. No major environmental enforcement actions have been identified as a primary concern.","flags":[],"sources":[]},"political":{"summary":"Medtronic's 2015 Ireland tax inversion — through the Covidien acquisition — represented one of the most prominent examples of a US company using an acquisition to reincorporate in a lower-tax jurisdiction. US Treasury subsequently issued rules in 2016 attempting to limit such inversions. Medtronic lobbied against the Affordable Care Act's medical device excise tax.","flags":["tax_inversion_triggered_treasury_rule_changes","medical_device_excise_tax_aca_opposition"],"sources":[]},"legal":{"summary":"2006: Medtronic paid $40 million to DOJ for kickbacks to orthopedic surgeons. 2017: Medtronic paid $190 million to DOJ for kickbacks to spine surgeons — the largest medical device kickback settlement at that time. The conduct covered 2006-2017 and involved payments disguised as consulting fees, royalties, and research grants. INFUSE-related litigation: Medtronic settled class action and individual claims related to undisclosed adverse events in its INFUSE bone protein product.","flags":["190m_spinal_kickback_2017_largest_at_time","40m_orthopedic_kickback_2006","infuse_adverse_event_suppression_spine_journal_documented"],"sources":["https://www.justice.gov/opa/pr/medtronic-agrees-pay-190-million-resolve-kickback-lawsuit"]},"tax":{"summary":"Medtronic's 2015 reincorporation in Ireland moved the company's legal domicile from Minnesota to Dublin while maintaining most operations in the US. Ireland's 12.5% corporate tax rate vs. the then-35% US statutory rate created documented tax savings estimated at $1+ billion annually.","flags":["ireland_12_5pct_vs_us_35pct_tax_rate","1b_estimated_annual_tax_savings"],"sources":[]},"executives":{"summary":"CEO Geoffrey Martha leads Medtronic. The physician kickback schemes covered multiple leadership periods. No Medtronic executive was personally criminally charged for the kickback settlements. The physician-authors who received Medtronic payments and published favorable INFUSE studies faced academic and professional scrutiny.","flags":["no_executive_criminal_charges_kickback_settlements","infuse_physician_authors_medtronic_payments_documented"],"sources":[]},"connections":{"summary":"Medtronic's physician kickback schemes represent a documented structural problem in medical device marketing where physician influence over procedure decisions creates inherent conflicts of interest. The INFUSE case specifically shows how Medtronic's payments to physician-researchers shaped the clinical literature on its own products — physicians who received Medtronic funding authored studies that the Spine journal found had systematically omitted adverse events.","flags":["physician_conflict_of_interest_structural_problem_documented","manufacturer_funded_research_adverse_event_omission"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"The Spine journal's 2011 special issue alleged that Medtronic's INFUSE adverse event data was known to the company before publication of studies that omitted it — and that the physician-authors who concealed adverse events received a combined $210 million in Medtronic royalties and consulting fees over the study period.","flags":["210m_physician_royalties_during_infuse_adverse_event_suppression","unnecessary_surgery_kickback_incentive_alleged"],"sources":[]},"health_record":{"summary":"INFUSE bone morphogenetic protein (rhBMP-2) is used in spinal fusion surgeries to stimulate bone growth. The 2011 Spine journal investigation found that adverse events documented in internal clinical trial data — including ectopic bone growth, cancer risk association, retrograde ejaculation, and bone resorption — were systematically omitted from published studies. Patients who received INFUSE based on the published favorable evidence had not been informed of these risks.","flags":["infuse_ectopic_bone_growth_adverse_event_suppressed","infuse_cancer_risk_retrograde_ejaculation_suppressed","kickback_marginal_indication_surgery_incentive"],"sources":[]},"alternatives":{"cheaper":["Before spinal surgery: ask your spine surgeon specifically about their financial relationships with Medtronic and other device manufacturers — the Physician Sunshine Act requires disclosure"],"healthier":["Before spinal surgery: physical therapy, pain management, and non-surgical alternatives should be documented as exhausted before elective procedures"],"diy":["Check physician financial disclosures at OpenPaymentsData.cms.gov","The FDA's MAUDE database contains adverse event reports for medical devices including Medtronic products"]},"timeline":[{"year":2006,"event":"$40M DOJ settlement for kickbacks to orthopedic surgeons","severity":"high","source_url":""},{"year":2011,"event":"Spine journal publishes special issue documenting INFUSE adverse event suppression; physician-authors received $210M Medtronic payments","severity":"critical","source_url":""},{"year":2015,"event":"$49.9B Covidien acquisition; Medtronic reincorporates in Dublin, Ireland — prominent tax inversion","severity":"high","source_url":""},{"year":2017,"event":"$190M DOJ kickback settlement — largest medical device kickback settlement at time","severity":"critical","source_url":"https://www.justice.gov/opa/pr/medtronic-agrees-pay-190-million-resolve-kickback-lawsuit"}],"community_impact":{"displacement":"Patients who underwent spinal surgeries influenced by Medtronic's physician kickback scheme may have had procedures they did not clinically need. Patients who received INFUSE based on published studies that suppressed adverse event data were not able to make informed consent decisions.","price_illusion":"Medtronic's INFUSE product was sold and prescribed based on a clinical evidence base that the Spine journal found was systematically distorted by payments to physician-authors who omitted adverse events.","tax_math":"Medtronic's Ireland reincorporation saves an estimated $1+ billion annually in US corporate taxes. The company remains primarily a US operation — manufacturing in Minnesota, employing US workers, generating significant US revenues.","wealth_velocity":"Medtronic is publicly traded on the New York Stock Exchange. Its Ireland reincorporation concentrated tax savings that flow to shareholders."},"cost_absorption":{"who_benefited":[{"group":"Medtronic shareholders","how":"Physician kickbacks drove device sales; Ireland tax inversion saves estimated $1B+ annually; INFUSE favorable literature drove adoption"},{"group":"Spine surgeons receiving kickbacks","how":"$190M total documented kickback payments across consulting, royalties, and research payments"}],"who_paid":[{"group":"Patients with INFUSE-related adverse events","how":"Ectopic bone growth, cancer risk, male infertility — adverse events suppressed in manufacturer-funded literature; no informed consent possible"},{"group":"US taxpayers","how":"$1B+ annual corporate tax savings from Ireland reincorporation reduces US public revenue while Medtronic maintains primarily US operations"}],"the_gap":"Medtronic paid $210 million to the doctors who wrote the clinical studies on their INFUSE product. Those doctors left out the cancer risk. And the infertility risk. And the ectopic bone growth. Medtronic paid $190 million for paying other doctors to use their spine products. No executive was criminally charged. The company is legally headquartered in Ireland and saves over a billion dollars a year in US taxes. It was founded in Minneapolis."}});
w('profiles_v6','rio-tinto',{"brand_name":"Rio Tinto","brand_slug":"rio-tinto","parent_company":"Rio Tinto plc / Rio Tinto Limited","ultimate_parent":"Rio Tinto plc (UK) / Rio Tinto Limited (Australia)","overall_concern_level":"significant","profile_type":"database","generated_headline":"RIO TINTO HAD ARCHAEOLOGICAL SURVEYS SHOWING JUUKAN GORGE WAS 46,000 YEARS OLD — THEY BLEW IT UP TO MINE IRON ORE AND SAID THEY WERE 'SORRY'","executive_summary":"Rio Tinto plc is one of the world's largest mining companies. On May 24, 2020, Rio Tinto detonated explosives at Juukan Gorge in the Pilbara region of Western Australia — destroying two rock shelters that had provided evidence of continuous Aboriginal habitation for 46,000 years, making them among the oldest known human occupation sites in Australia. Rio Tinto had received archaeological surveys confirming the sites' extraordinary cultural and historical significance and had been explicitly warned by the Puutu Kunti Kurrama and Pinikura (PKKP) people that the sites were sacred. The destruction was legal under a 1972 Western Australia law. CEO Jean-Sébastien Jacques and two other senior executives resigned following shareholder and public backlash. Australia subsequently amended the Aboriginal Heritage Act in 2021. A 2021-2022 independent review documented a pervasive culture of sexual harassment, bullying, and racism at Rio Tinto's Australian operations.","verdict_tags":["juukan_gorge_46000_year_site_destroyed","ceo_resigned_two_executives","legal_under_1972_law_amended_2021","pkkp_people_explicitly_warned","21pct_women_sexual_harassment_broderick_review"],"concern_flags":{"labor":true,"environmental":true,"political":true,"tax":true,"health":false,"legal":true},"labor":{"summary":"A 2021-2022 independent review commissioned by Rio Tinto and conducted by former sex discrimination commissioner Elizabeth Broderick documented a pervasive culture of sexual harassment, bullying, and racism at Rio Tinto's Australian operations. The review found 21% of women experienced sexual harassment; 28% experienced bullying.","flags":["21pct_women_sexual_harassment_broderick_review","28pct_bullying_documented","racism_documented_australian_operations"],"sources":["https://www.riotinto.com/en/invest/reports/broderick-report"]},"environmental":{"summary":"Mining is inherently an environmentally transformative activity. Rio Tinto's Juukan Gorge destruction is one dimension of its environmental footprint. The company's tailings storage facilities represent ongoing environmental management obligations across multiple continents.","flags":["tailings_storage_facilities_multiple_continents"],"sources":[]},"political":{"summary":"The Juukan Gorge destruction was legal under Western Australia's 1972 Aboriginal Heritage Act — which allowed mineral extraction to proceed over Aboriginal heritage sites with ministerial approval. The PKKP people's objections were legally subordinate to the mining company's approved operational plan. The destruction triggered Australian Senate inquiries and the 2021 amendment of the Aboriginal Heritage Act.","flags":["legal_under_1972_law_indigenous_rights_subordinated","senate_inquiry_triggered","2021_wa_aboriginal_heritage_act_amendment"],"sources":[]},"legal":{"summary":"Rio Tinto's destruction of Juukan Gorge was legal under existing Australian law at the time — no criminal charges were filed. The company reached a confidential settlement with the PKKP people, reportedly including financial compensation, cultural preservation commitments, and joint management arrangements. The WA Aboriginal Heritage Act Amendment Act 2021 subsequently strengthened protections.","flags":["juukan_destruction_legal_at_time","pkkp_settlement_confidential","no_criminal_charges","2021_wa_act_strengthened_post_juukan"],"sources":[]},"tax":{"summary":"Rio Tinto is dual-listed on the London and Australian stock exchanges. The company has faced scrutiny for its transfer pricing arrangements between its Australian iron ore production operations and its Singapore marketing hub — a structure the Australian Taxation Office has investigated.","flags":["australia_singapore_transfer_pricing_ato_scrutiny"],"sources":[]},"executives":{"summary":"CEO Jean-Sébastien Jacques and two executives resigned in September 2020 following shareholder pressure. Jacques' initial response — expressing 'deep regret' while linking the destruction to 'misunderstandings' — was condemned by the PKKP people and shareholders. Jakob Stausholm became CEO in January 2021.","flags":["jacques_misunderstandings_response_condemned","three_senior_executives_resigned_shareholder_pressure"],"sources":["https://www.theguardian.com/australia-news/2020/sep/11/rio-tinto-chief-executive-jean-sebastien-jacques-to-resign-over-juukan-gorge"]},"connections":{"summary":"Rio Tinto's iron ore feeds Chinese steel production — approximately 60% of its iron ore goes to China. The company's Oyu Tolgoi copper and gold project in Mongolia is one of the world's largest undeveloped copper deposits.","flags":["60pct_iron_ore_china_steel_dependence"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"The PKKP people and their advocates have alleged that Rio Tinto's decision-making process treated Juukan Gorge as a cost-benefit calculation — weighing the mineral value against heritage preservation — rather than as an absolute limit. Internal Rio Tinto communications released to Australian Senate investigators showed that concerns about the heritage significance had been raised internally and were known to operational decision-makers before the detonation.","flags":["cost_benefit_heritage_calculation_alleged","internal_communications_heritage_concerns_known_before_detonation"],"sources":[]},"health_record":{"summary":"The Broderick review's documented sexual harassment and bullying rates — 21% of women experiencing sexual harassment — represent occupational health harm to Rio Tinto's own workforce. The destruction of Juukan Gorge is an irreversible cultural health harm to the PKKP people — loss of a site that represented 46,000 years of their ancestry and spiritual connection.","flags":["21pct_women_sexual_harassment_occupational_health","pkkp_irreversible_cultural_harm"],"sources":[]},"alternatives":{"cheaper":["Rio Tinto is B2B — consumers do not directly choose Rio Tinto. The alternative is policy: mandatory free, prior, and informed consent for Indigenous heritage sites before mining approval."],"healthier":["Support the UN Declaration on the Rights of Indigenous Peoples implementation in Australia and other resource-extraction jurisdictions"],"diy":["If you are an investor in Rio Tinto: the Broderick report and Juukan Gorge response are documented ESG failures; shareholder resolutions on Indigenous heritage and workplace culture have been active at Rio Tinto's AGMs"]},"timeline":[{"year":2013,"event":"Rio Tinto archaeological survey confirms Juukan Gorge's extraordinary significance — 46,000 years of continuous habitation evidence","severity":"critical","source_url":""},{"year":2014,"event":"PKKP people formally registered their objection to disturbance of Juukan Gorge sites with Rio Tinto","severity":"critical","source_url":""},{"year":2020,"event":"May 24: Rio Tinto detonates explosives at Juukan Gorge, destroying the 46,000-year-old rock shelters to access iron ore. September: CEO Jacques and two executives resign under shareholder pressure.","severity":"critical","source_url":"https://www.theguardian.com/australia-news/2020/sep/11/rio-tinto-chief-executive-jean-sebastien-jacques-to-resign-over-juukan-gorge"},{"year":2021,"event":"Broderick review documents 21% sexual harassment, 28% bullying in Australian operations. WA Aboriginal Heritage Act amended — Juukan Gorge destruction cited as direct catalyst.","severity":"critical","source_url":""}],"community_impact":{"displacement":"The destruction of Juukan Gorge is irreversible. A site documenting 46,000 years of continuous Aboriginal habitation no longer exists. The PKKP people described the loss as 'devastating' and equivalent to the destruction of their identity.","price_illusion":"Rio Tinto's iron ore is priced on global commodity markets. The destruction of Juukan Gorge — valued by Rio Tinto's operational planning as an obstacle to iron ore extraction — was a cost-benefit decision in which the cultural value to the PKKP people was legally subordinate to the mineral extraction value.","tax_math":"Rio Tinto's Australian-Singapore transfer pricing — under ATO scrutiny — potentially reduces Australian taxable income from iron ore sales.","wealth_velocity":"Rio Tinto's dual-listed structure concentrates ownership among UK and Australian institutional shareholders. The iron ore extracted from the Pilbara generates dividends that flow to London and Sydney shareholders."},"cost_absorption":{"who_benefited":[{"group":"Rio Tinto shareholders","how":"Iron ore extracted from the site that required Juukan Gorge's destruction; mineral value accessed through legal but irreversible heritage destruction"}],"who_paid":[{"group":"Puutu Kunti Kurrama and Pinikura people","how":"Irreversible loss of a 46,000-year-old site of ancestral significance; described by PKKP elders as loss of their identity and history"}],"the_gap":"Rio Tinto had archaeological surveys telling them Juukan Gorge was 46,000 years old. The PKKP people had formally objected. Rio Tinto detonated it anyway because the law let them. The CEO called it a misunderstanding. The PKKP people called it the destruction of their history. Three executives resigned after the shareholders pushed. No criminal charges were filed. The site does not exist anymore."}});
w('profiles_v6','mondelez-international',{"brand_name":"Mondelez International","brand_slug":"mondelez-international","parent_company":"Mondelez International, Inc.","ultimate_parent":"Mondelez International, Inc.","overall_concern_level":"moderate","profile_type":"database","generated_headline":"MONDELEZ CLOSED THE CADBURY FACTORY IT PROMISED TO KEEP OPEN WITHIN WEEKS OF ACQUIRING IT — AND PAID $13 MILLION FOR BRIBING INDIAN GOVERNMENT OFFICIALS","executive_summary":"Mondelez International, Inc. is one of the world's largest snack food companies — producing Oreo, Cadbury, Toblerone, and dozens of other major brands — spun off from Kraft Foods in 2012. In 2010, Kraft Foods acquired Cadbury PLC in a hostile takeover for £11.5 billion. During the acquisition, Kraft CEO Irene Rosenfeld explicitly promised UK parliamentarians that it would keep open the Somerdale factory near Bristol. Within weeks of completing the acquisition, Kraft reversed this commitment and closed Somerdale — eliminating approximately 400 jobs. The closure triggered a parliamentary inquiry and the UK Takeover Code was subsequently amended. As Mondelez, the company paid $13 million to the DOJ in 2022 to resolve FCPA violations for bribing Indian government officials. Mondelez's cocoa supply chain shares the same documented West African child labor problem as Nestlé and Lindt.","verdict_tags":["somerdale_factory_closed_weeks_after_promise_to_keep_open","13m_fcpa_india_bribery_2022","cadbury_hostile_takeover_11_5b","west_africa_cocoa_child_labor_supply_chain","uk_takeover_code_changed_cadbury_closure_cited"],"concern_flags":{"labor":true,"environmental":false,"political":true,"tax":true,"health":true,"legal":true},"labor":{"summary":"The Somerdale closure — eliminating approximately 400 jobs within weeks of Kraft's explicit parliamentary commitment to keep the factory open — is the most documented labor-related failure in Mondelez's history.","flags":["somerdale_400_jobs_closed_after_promise"],"sources":["https://www.theguardian.com/business/2010/mar/31/kraft-somerdale-cadbury-closure"]},"environmental":{"summary":"Mondelez's cocoa supply chain involves sourcing from Ivory Coast and Ghana where deforestation is a documented side effect of cocoa farming expansion. The company's palm oil supply chain has the same deforestation and labor concerns as other major palm oil buyers.","flags":["cocoa_deforestation_ivory_coast_ghana","palm_oil_deforestation_labor"],"sources":[]},"political":{"summary":"The Somerdale closure became a cause célèbre in British political discourse. UK Takeover Code changes subsequently required acquirers to honor stated intentions for a longer period.","flags":["uk_takeover_code_changed_cadbury_closure_cited"],"sources":[]},"legal":{"summary":"August 2022: Mondelez International agreed to pay $13 million to the DOJ and SEC to resolve FCPA violations — Mondelez's subsidiary in India had paid approximately $1.7 million in bribes to Indian government officials to obtain licenses and approvals. The DOJ entered into a non-prosecution agreement with Mondelez rather than criminal charges.","flags":["13m_fcpa_india_non_prosecution_agreement","1_7m_india_government_bribes"],"sources":["https://www.justice.gov/opa/pr/mondelez-international-inc-agrees-pay-13-million-resolve-foreign-corrupt-practices-act"]},"tax":{"summary":"Mondelez's separation from Kraft Foods in 2012 involved significant IP restructuring — Mondelez holds major brand IP through international structures that concentrate royalty income in favorable jurisdictions.","flags":["brand_ip_international_structures"],"sources":[]},"executives":{"summary":"CEO Dirk Van de Put leads Mondelez. His predecessor Irene Rosenfeld led the Cadbury acquisition and made the Somerdale promise. No Mondelez executive was personally charged in the India FCPA matter.","flags":["rosenfeld_somerdale_promise_cited","no_executive_charges_india_fcpa"],"sources":[]},"connections":{"summary":"Mondelez's cocoa supply chain connects it to the same West African child labor ecosystem documented for Nestlé, Mars, Lindt, and Hershey. The Harkin-Engel Protocol has failed to eliminate child labor since 2001 — a commitment all these brands made and missed.","flags":["same_west_africa_cocoa_ecosystem_nestle_lindt_mars","harkin_engel_failed_2001_all_companies"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Former Cadbury employees and UK trade union representatives have alleged that Kraft's Somerdale commitment was never genuinely intended to be honored — that the commitment was made specifically to smooth parliamentary concerns during a contested acquisition and that internal Kraft planning documents had already incorporated the closure.","flags":["somerdale_commitment_never_genuine_alleged"],"sources":[]},"health_record":{"summary":"Mondelez's portfolio — Oreo, Chips Ahoy, Ritz — consists primarily of ultra-processed foods associated in population studies with elevated rates of chronic disease. The cocoa child labor supply chain involves hazardous agricultural work by children including machete use and pesticide exposure.","flags":["ultra_processed_food_chronic_disease_association","cocoa_child_labor_hazardous_agricultural_work"],"sources":[]},"alternatives":{"cheaper":["Store brand biscuits and chocolate — same food category at lower price","Local and regional confectionery brands for chocolate"],"healthier":["Tony's Chocolonely for chocolate — independently verified child-labor-free cocoa mission"],"diy":["Check any chocolate brand's cocoa supply chain at goodchocolateguide.org before purchase"]},"timeline":[{"year":2010,"event":"January: Kraft Foods completes hostile takeover of Cadbury for £11.5B; CEO Rosenfeld had told MPs Somerdale would remain open. March: Somerdale closure announced within weeks; 400 jobs eliminated.","severity":"critical","source_url":"https://www.theguardian.com/business/2010/mar/31/kraft-somerdale-cadbury-closure"},{"year":2012,"event":"Kraft spins off international snack business as Mondelez International","severity":"neutral","source_url":""},{"year":2022,"event":"August: $13M DOJ/SEC FCPA non-prosecution agreement for bribing Indian government officials","severity":"high","source_url":"https://www.justice.gov/opa/pr/mondelez-international-inc-agrees-pay-13-million-resolve-foreign-corrupt-practices-act"}],"community_impact":{"displacement":"The Somerdale closure displaced approximately 400 workers from a factory that Kraft had explicitly committed to keep open during parliamentary testimony.","price_illusion":"Cadbury chocolate carries a premium associated with British heritage. Under Kraft/Mondelez ownership, that heritage has been sustained as a marketing asset while the operational practices that created it were not continued.","tax_math":"Mondelez's international IP structures for its Oreo, Cadbury, and other brand royalties concentrate income in favorable jurisdictions.","wealth_velocity":"Mondelez is publicly traded with institutional and retail shareholder ownership globally. The Cadbury acquisition premium transferred one of Britain's most beloved food brands to a US company that closed a factory it promised to keep open."},"cost_absorption":{"who_benefited":[{"group":"Kraft/Mondelez shareholders","how":"Cadbury brand portfolio acquired; Somerdale cost saved through closure despite promise; India licensing obtained through bribes"}],"who_paid":[{"group":"400 Somerdale workers","how":"Jobs eliminated weeks after company committed to parliament they would be preserved"},{"group":"West African child cocoa laborers","how":"Hazardous agricultural work supplying Cadbury and Milka cocoa supply chain"}],"the_gap":"Kraft's CEO told UK parliament Somerdale would stay open. The takeover completed. Somerdale closed within weeks. The Takeover Panel said they couldn't enforce it. The UK changed the Takeover Code. Mondelez paid $13 million for bribing Indian government officials. Their Cadbury chocolate supply chain has the same West African child labor problem as every other chocolate company that's been promising to fix it since 2001."}});
w('profiles_v6','sanofi',{"brand_name":"Sanofi","brand_slug":"sanofi","parent_company":"Sanofi S.A.","ultimate_parent":"Sanofi S.A.","overall_concern_level":"significant","profile_type":"database","generated_headline":"SANOFI KNEW SINCE THE 1980s THAT DEPAKINE CAUSED BIRTH DEFECTS — 30,000 CHILDREN IN FRANCE WERE BORN WITH DISORDERS — AND THE COMPANY WAS CONVICTED OF AGGRAVATED DECEIT IN 2022","executive_summary":"Sanofi S.A. is one of the world's largest pharmaceutical companies, headquartered in Paris. Its epilepsy drug valproate (sold as Depakine in France, Epilim in the UK, Depakote in the US) has been prescribed to pregnant women for decades — despite documented knowledge that it causes severe birth defects and developmental disorders. Internal Sanofi documents and regulatory investigations established that the company had warnings about valproate's teratogenic risks since at least the early 1980s. An estimated 30,000 children in France were born with Depakine-related disorders between 1967 and 2018 — including neural tube defects, skeletal abnormalities, autism spectrum disorder, and developmental delays. In 2022, a French criminal court convicted Sanofi of 'tromperie aggravée' (aggravated deceit) for failing to adequately warn of risks and fined it €2.7 million — the maximum available penalty under French law at the time.","verdict_tags":["depakine_30000_children_birth_defects_france","warnings_known_1980s_continued_without_adequate_disclosure","2022_french_criminal_conviction_aggravated_deceit","2_7m_maximum_french_penalty","neural_tube_defects_autism_developmental_disorders"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":true,"legal":true},"labor":{"summary":"Sanofi employs approximately 91,000 people globally. No major documented systemic labor violations have been identified as a primary concern.","flags":[],"sources":[]},"environmental":{"summary":"Sanofi's pharmaceutical manufacturing generates chemical waste streams. No major environmental enforcement actions have been identified as a primary concern.","flags":[],"sources":[]},"political":{"summary":"The Depakine scandal generated sustained political pressure in France — a parliamentary inquiry, regulatory reform, and the creation of a dedicated compensation fund. The French Medicines Agency (ANSM) was also investigated for the adequacy of its regulatory oversight. A Senate report criticized both Sanofi and French regulatory authorities.","flags":["ansm_regulatory_inadequacy_investigated","senate_report_sanofi_ansm_criticized"],"sources":[]},"legal":{"summary":"January 2022: A Paris criminal court convicted Sanofi of 'tromperie aggravée' (aggravated deceit) for failing to adequately warn of valproate's teratogenic risks. The court imposed fines of €2.7 million — the maximum available under French criminal law for this offense at the time. The French government established the Valproate National Compensation Fund (FIVA) to compensate affected families — funded by Sanofi and the French state. In the UK, litigation against Sanofi for Epilim has been pursued by affected families.","flags":["2022_criminal_conviction_aggravated_deceit","2_7m_maximum_penalty_characterized_shockingly_low","fiva_compensation_fund_disputed_adequacy","uk_epilim_litigation_ongoing"],"sources":[]},"tax":{"summary":"Sanofi is a French company with significant pharmaceutical IP held through international structures. The company uses Irish, Swiss, and other favorable-jurisdiction entities for IP management.","flags":["pharmaceutical_ip_international_structures"],"sources":[]},"executives":{"summary":"CEO Paul Hudson leads Sanofi. No individual Sanofi executive was personally convicted in the 2022 criminal proceedings — the conviction was at the corporate entity level. The criminal fine of €2.7 million represents the maximum available to the court — critics note this ceiling bears no proportionality to either Sanofi's revenues or the harm caused.","flags":["no_individual_conviction_corporate_entity_only","2_7m_ceiling_disproportionate_to_harm_and_revenue"],"sources":[]},"connections":{"summary":"Valproate is a widely prescribed drug for epilepsy and bipolar disorder globally — the Depakine/Epilim/Depakote issue has international dimensions beyond France. UK regulatory investigations have found similar patterns of inadequate warning to pregnant women. Sanofi's Zantac (ranitidine) product — found in 2020 to contain NDMA, a potential carcinogen — represents a separate product safety concern.","flags":["valproate_international_inadequate_warning_uk_also","zantac_ranitidine_ndma_carcinogen_recall_2020"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Affected families and their legal advocates have alleged that Sanofi's internal documents show the company received explicit warnings about valproate's teratogenic effects in the early 1980s and made commercial decisions to delay or minimize warning updates to protect Depakine's market position.","flags":["1980s_internal_warnings_commercial_decision_delay_alleged","fiva_contribution_inadequate_alleged"],"sources":[]},"health_record":{"summary":"Valproate is a known teratogen — it causes birth defects when taken during pregnancy. The documented effects include: neural tube defects (spina bifida, anencephaly), craniofacial abnormalities, autism spectrum disorder (3x elevated risk), developmental delays and intellectual disability. The French government's Valproate National Report estimated 30,000 children in France were born with valproate-related disorders between 1967 and 2018. Women were prescribed Depakine for seizure disorders without adequate warning of these documented risks for decades.","flags":["30000_children_france_birth_defects_estimated","3x_autism_spectrum_disorder_risk","neural_tube_defects_spina_bifida_documented"],"sources":[]},"alternatives":{"cheaper":["For epilepsy management: other antiseizure medications do not carry the same teratogenic risk profile; lamotrigine has been extensively studied as a safer alternative in pregnancy — neurologist consultation is essential"],"healthier":["The epilepsy and pregnancy decision is a medical one requiring specialist neurologist input — the Epilepsy Foundation (epilepsy.com) provides evidence-based guidance"],"diy":["If you or a family member took Depakine/Epilim/Depakote during pregnancy and a child has developmental issues: the French FIVA fund and UK litigation processes are available"]},"timeline":[{"year":1982,"event":"Estimated period from which internal Sanofi documents later showed awareness of teratogenic risk based on published scientific evidence and regulatory correspondence","severity":"critical","source_url":""},{"year":2014,"event":"French ANSM restricts valproate use in pregnancy and requires annual attestation from women of childbearing age","severity":"high","source_url":""},{"year":2017,"event":"French government orders national compensation fund study; confirms scale of harm — estimated 30,000 children affected","severity":"critical","source_url":""},{"year":2020,"event":"Sanofi recalls Zantac (ranitidine) globally after FDA finds NDMA carcinogen contamination — separate product safety crisis","severity":"critical","source_url":""},{"year":2022,"event":"January: Paris criminal court convicts Sanofi of aggravated deceit; €2.7M fine (maximum available); no individual convictions","severity":"critical","source_url":""}],"community_impact":{"displacement":"An estimated 30,000 children in France were born with disorders associated with their mother's use of Depakine during pregnancy. These families have navigated disability services, specialist care, and educational support without knowing for years that the cause was a drug prescribed without adequate safety warning.","price_illusion":"Depakine was prescribed as a safe and effective epilepsy treatment. The French criminal court found that Sanofi's disclosure of its risks to pregnant women was criminally inadequate despite documented internal knowledge of those risks since the early 1980s.","tax_math":"The French government's FIVA compensation fund is funded partly by the French state — meaning French taxpayers are funding compensation for harm caused by inadequate pharmaceutical disclosure. The criminal fine of €2.7 million bears no proportionality to a company with €43+ billion in annual revenue.","wealth_velocity":"Sanofi's revenue from Depakine sales during the decades of inadequate warning funded shareholder dividends. The families of children born with Depakine-related disorders bear the lifetime cost of their children's conditions."},"cost_absorption":{"who_benefited":[{"group":"Sanofi shareholders","how":"Revenue from Depakine sales during the period of inadequate risk disclosure; criminal fine of €2.7M is a fraction of revenue from the drug"}],"who_paid":[{"group":"30,000 French children and their families","how":"Neural tube defects, autism, developmental disorders associated with valproate exposure during pregnancy without adequate informed consent"},{"group":"French taxpayers","how":"State contribution to FIVA compensation fund covering portion of harm that Sanofi's maximum €2.7M fine does not address"}],"the_gap":"Sanofi knew Depakine caused birth defects. The evidence was in the scientific literature from the 1970s. Internal documents showed awareness in the 1980s. 30,000 children in France were born with disorders. The criminal fine was €2.7 million — the maximum allowed by law. Sanofi's revenue is €43 billion. No individual executive was convicted. The mothers who took Depakine didn't know."}});
w('profiles_v6','diageo',{"brand_name":"Diageo","brand_slug":"diageo","parent_company":"Diageo plc","ultimate_parent":"Diageo plc","overall_concern_level":"moderate","profile_type":"database","generated_headline":"DIAGEO BRIBED OFFICIALS IN INDIA THAILAND AND SOUTH KOREA AND PAID $16 MILLION — IT ALSO CONTROLS 30% OF GLOBAL PREMIUM SPIRITS WITH PERNOD RICARD AND MARKETS TO YOUNG AUDIENCES","executive_summary":"Diageo plc is the world's largest spirits company by volume and revenue, headquartered in London. Its brands include Johnnie Walker, Guinness, Smirnoff, Tanqueray, and Don Julio — spanning Scotch whisky, beer, vodka, gin, rum, and tequila. In July 2011, Diageo's subsidiaries agreed to pay $16.4 million to the SEC and DOJ to resolve FCPA violations covering bribes paid to government officials in India, Thailand, and South Korea to secure licenses, regulatory approvals, and preferential treatment. Together with Pernod Ricard, Diageo controls approximately 30% of global premium spirits. Diageo's documented marketing practices — particularly in emerging markets — have drawn regulatory and public health criticism for targeting younger consumers.","verdict_tags":["16_4m_fcpa_india_thailand_south_korea","30pct_global_spirits_pernod_ricard_duopoly","underage_marketing_emerging_markets_documented","water_extraction_drought_stressed_regions"],"concern_flags":{"labor":false,"environmental":true,"political":true,"tax":true,"health":true,"legal":true},"labor":{"summary":"Diageo employs approximately 27,000 people globally. No major documented systemic labor violations have been identified as a primary concern.","flags":[],"sources":[]},"environmental":{"summary":"Spirits production is water-intensive. Diageo's Don Julio and Casamigos tequila production in Jalisco — where agave farming contributes to significant water stress — is a documented environmental concern.","flags":["scotch_highland_water_extraction","jalisco_tequila_groundwater_depletion_documented"],"sources":[]},"political":{"summary":"Diageo's FCPA violations covered three distinct markets and three distinct government systems — indicating a systematic approach to bribery in markets where regulatory approvals, import licenses, and government-controlled distribution created incentive structures for corruption. The company lobbies against alcohol advertising restrictions, minimum unit pricing legislation, and excise tax increases.","flags":["three_country_systematic_bribery_different_government_types","minimum_unit_pricing_scotland_opposition","advertising_restriction_lobbying"],"sources":["https://www.sec.gov/news/press-release/2011-154"]},"legal":{"summary":"July 2011: Three Diageo subsidiaries entered deferred prosecution agreements with the DOJ and agreed to pay $16.4 million — $11.3 million to the DOJ and $5.1 million disgorgement to the SEC. The violations covered payments to government officials in India, Thailand, and South Korea. No Diageo executive was personally charged. The company has faced UK Advertising Standards Authority enforcement actions for social media campaigns that reached underage audiences.","flags":["16_4m_fcpa_deferred_prosecution_agreements","11_3m_doj_5_1m_sec_disgorgement","no_executive_charges","uk_asa_enforcement_social_media_underage"],"sources":["https://www.sec.gov/news/press-release/2011-154"]},"tax":{"summary":"Diageo is UK-incorporated and pays UK corporate taxes as a primary domicile. The company's international brand IP — particularly for Scotch whisky — is managed through structures that optimize royalty income.","flags":["scotch_whisky_uk_tax_provisions","brand_ip_royalty_optimization"],"sources":[]},"executives":{"summary":"CEO Debra Crew leads Diageo. Her predecessor Ivan Menezes led the company for a decade. The FCPA violations occurred under prior leadership. No Diageo executive was personally charged for the FCPA violations.","flags":["no_executive_fcpa_charges"],"sources":[]},"connections":{"summary":"Diageo and Pernod Ricard together control approximately 30% of global premium spirits — a duopoly with extraordinary marketing reach and pricing power. Both companies have faced similar FCPA enforcement actions. Both lobby against the same alcohol advertising restrictions and minimum pricing legislation.","flags":["pernod_ricard_30pct_duopoly_joint_lobbying_fcpa"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Public health researchers have alleged that Diageo's marketing in sub-Saharan Africa specifically targets lower-income consumers with high-alcohol-content products at low price points. Digital marketing researchers have alleged that Diageo's social media campaigns on Instagram and TikTok reach underage audiences at rates that violate its own stated marketing standards.","flags":["africa_high_alcohol_low_income_marketing_alleged","instagram_tiktok_underage_reach_alleged"],"sources":[]},"health_record":{"summary":"The global alcohol industry's contribution to public health harm is documented: alcohol causes approximately 3 million deaths annually (WHO), is the leading risk factor for death among people aged 15-49, and is causally linked to liver disease, multiple cancers, cardiovascular disease, and alcohol use disorder. Diageo, controlling approximately 15% of global premium spirits, is a significant actor in these outcomes.","flags":["3m_deaths_annually_alcohol_global_who","15_49_age_group_leading_risk_factor"],"sources":["https://www.who.int/news-room/fact-sheets/detail/alcohol"]},"alternatives":{"cheaper":["Local craft spirits in your region — independent distilleries with transparent ownership; money stays local","Non-alcoholic spirits (Seedlip, Lyre's, Athletic Brewing for non-alcoholic beer)"],"healthier":["Reduction in alcohol consumption — WHO documents no safe level of alcohol consumption"],"diy":["If you see Diageo advertising on social media that appears to target underage audiences: report to the UK Advertising Standards Authority or your national equivalent"]},"timeline":[{"year":1997,"event":"Diageo formed through merger of Guinness PLC and Grand Metropolitan; creates world's largest spirits company","severity":"neutral","source_url":""},{"year":2011,"event":"July: $16.4M FCPA settlement — three Diageo subsidiaries enter deferred prosecution agreements for bribing officials in India, Thailand, South Korea","severity":"critical","source_url":"https://www.sec.gov/news/press-release/2011-154"},{"year":2015,"event":"Diageo acquires Don Julio tequila; expands into premium tequila market with Jalisco water stress implications","severity":"neutral","source_url":""},{"year":2019,"event":"UK Advertising Standards Authority enforcement actions against Diageo campaigns for reaching underage audiences on social media","severity":"high","source_url":""}],"community_impact":{"displacement":"Diageo's tequila production in Jalisco's Lowlands region contributes to documented water stress from agave farming and distillation that affects local agricultural communities.","price_illusion":"Diageo's premium spirits are priced as lifestyle products. The price does not reflect the water extraction from drought-stressed communities, the FCPA bribes paid to access regulatory-controlled markets, or the public health costs of alcohol consumption at population scale.","tax_math":"Diageo's UK corporate tax payments benefit from Scotch whisky production provisions and international IP arrangements. The $16.4 million FCPA settlement is tax-deductible as a business expense.","wealth_velocity":"Diageo is listed on the London Stock Exchange with broad UK and international institutional ownership. Revenue from premium spirits brands consumed globally concentrates in London."},"cost_absorption":{"who_benefited":[{"group":"Diageo shareholders","how":"30% premium spirits market control; FCPA bribery enabled regulatory approvals in three markets; premiumization driving margin expansion"},{"group":"Government officials in India, Thailand, South Korea who received bribes","how":"Personal enrichment from payments enabling Diageo's regulatory market access"}],"who_paid":[{"group":"Consumers with alcohol use disorder","how":"Alcohol causes approximately 3 million deaths annually; Diageo's marketing contributes to consumption patterns at the company responsible for approximately 15% of premium spirits globally"}],"the_gap":"Diageo bribed officials in three countries to sell alcohol in those markets. They paid $16.4 million. No executive was charged. Together with Pernod Ricard they control 30% of global premium spirits. Their marketing has been found to reach underage audiences. Alcohol causes 3 million deaths annually. It is the leading cause of death for people aged 15-49. Diageo is the world's largest company selling it."}});
